mapper.select:
SELECT count(*)
FROM hm_query.fact_settlements fs
LEFT JOIN hm_query.dim_seller ds ON fs.supplier_id = ds.seller_id

    AND fs.supplier_id = #{supplierId}
    AND fs.state_id = #{stateId}
    AND fs.order_id = #{orderId}
    AND fs.currency = #{currency}
    AND (
        ds.seller_name LIKE CONCAT('%', #{q}, '%')
        OR fs.order_id LIKE CONCAT('%', #{q}, '%')
        OR fs.disbursement_reference LIKE CONCAT('%', #{q}, '%')
    )

SELECT fs.id, fs.supplier_id as "supplierId", ds.seller_name as "supplierName", ds.seller_tier as "supplierTier", fs.order_id as "orderId", fs.state_id as "stateId", fs.flow_id as "flowId", fs.order_amount as "orderAmount", fs.commission_amount as "commissionAmount", fs.platform_fee as "platformFee", fs.net_amount as "netAmount", fs.currency, fs.settlement_period_start as "settlementPeriodStart", fs.settlement_period_end as "settlementPeriodEnd", fs.disbursement_reference as "disbursementReference", fs.created_time as "createdTime" FROM hm_query.fact_settlements fs LEFT JOIN hm_query.dim_seller ds ON fs.supplier_id = ds.seller_id
AND fs.supplier_id = #{supplierId} AND fs.state_id = #{stateId} AND fs.order_id = #{orderId} AND fs.currency = #{currency} AND ( ds.seller_name LIKE CONCAT('%', #{q}, '%') OR fs.order_id LIKE CONCAT('%', #{q}, '%') OR fs.disbursement_reference LIKE CONCAT('%', #{q}, '%') )
${orderby} ${pagination}

SELECT count(*) FROM hm_query.fact_settlements
WHERE supplier_id = #{supplierId}
AND state_id = #{stateId}

SELECT count(*) FROM hm_query.fact_settlements
WHERE state_id IN ('PENDING', 'CALCULATING', 'CALCULATED', 'APPROVED')
AND supplier_id = #{supplierId}

SELECT fs.supplier_id as "supplierId", ds.seller_name as "supplierName", count(*) as "orderAmount", sum(fs.net_amount) as "netAmount", sum(fs.commission_amount) as "commissionAmount", sum(fs.platform_fee) as "platformFee" FROM hm_query.fact_settlements fs LEFT JOIN hm_query.dim_seller ds ON fs.supplier_id = ds.seller_id
AND fs.supplier_id = #{supplierId}
GROUP BY fs.supplier_id, ds.seller_name

SELECT count(*) FROM hm_query.fact_settlements
WHERE supplier_id = #{supplierId}
AND state_id = #{stateId}
